import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Meal {
  meal: string;
  name: string;
  calories: number;
  prepTime: string;
}

interface MealPlannerData {
  todayMeals: Meal[];
  calorieTotal: number;
}

export default function Widget() {
  const mealPlannerData = response.data as MealPlannerData;
  const { todayMeals, calorieTotal } = mealPlannerData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
            Daily Meal Planner
          </Typography>

          {todayMeals.map((meal, index) => (
            <Box key={index} sx={{ mb: 1 }}>
              <Typography variant="body1" fontWeight={500} color="text.primary">
                {meal.meal}: {meal.name}
              </Typography>
              <Stack direction="row" spacing={1}>
                <Chip label={`${meal.calories} kcal`} sx={{ fontSize: '11px', bgcolor: '#FFC107', color: '#FFFFFF' }} />
                <Chip label={meal.prepTime} sx={{ fontSize: '11px', bgcolor: '#FF5722', color: '#FFFFFF' }} />
              </Stack>
            </Box>
          ))}

          <Typography variant="body2" color="text.secondary" sx={{ mt: 2 }}>
            Total Calories: {calorieTotal} kcal
          </Typography>
        </Stack>
      </CardContent>
    </Card>
  );
}
